import React, { useEffect, useState } from 'react';
import { getSitios, deleteSitio } from './services/culturaService';

function App() {
  const [sitios, setSitios] = useState([]);

  useEffect(() => {
    cargarDatos();
  }, []);

  const cargarDatos = async () => {
    const datos = await getSitios();
    setSitios(datos);
  };

  const eliminar = async (id) => {
    if(window.confirm('¿Deseas eliminar este sitio cultural?')) {
      await deleteSitio(id);
      cargarDatos();
    }
  };

  return (
    <div style={{ padding: '20px', backgroundColor: '#f4f4f4', minHeight: '100vh' }}>
      <header style={{ textAlign: 'center', marginBottom: '30px' }}>
        <h1 style={{ color: '#d9534f' }}>Cultura La Paz - Panel de Control</h1>
        <p>Gestión de sitios culturales para el proyecto de grado</p>
      </header>

      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', 
        gap: '20px',
        maxWidth: '1200px',
        margin: '0 auto'
      }}>
        {sitios.length > 0 ? (
          sitios.map(sitio => (
            <div key={sitio._id} style={{ 
              backgroundColor: 'white', 
              padding: '20px', 
              borderRadius: '10px', 
              boxShadow: '0 4px 6px rgba(0,0,0,0.1)' 
            }}>
              <h3 style={{ marginTop: '0', color: '#333' }}>{sitio.nombre}</h3>
              <p style={{ color: '#666' }}>{sitio.descripcion}</p>
              <p><strong>📍 Ubicación:</strong> {sitio.ubicacion}</p>
              <button 
                onClick={() => eliminar(sitio._id)}
                style={{ 
                  backgroundColor: '#d9534f', 
                  color: 'white', 
                  border: 'none', 
                  padding: '10px 15px', 
                  borderRadius: '5px', 
                  cursor: 'pointer',
                  width: '100%'
                }}
              >
                Eliminar Sitio
              </button>
            </div>
          ))
        ) : (
          <p style={{ textAlign: 'center', gridColumn: '1 / -1' }}>No hay sitios registrados o el servidor está apagado.</p>
        )}
      </div>
    </div>
  );
}

export default App;
